  subt.qual = type->qual;
  subt.texp = type->texp ? type->texp->sub : nullptr;

  if (auto p_ = type->texp->dcst<PointerType>()) {
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    if (p->len == ArrayType::kUnLen)
      return llvm::PointerType::get(mCtx, 0);
    return llvm::ArrayType::get(self(&subt), p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto&& param : p->params)
      pty.push_back(self(param));
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }''', '''
  if (auto p = type->texp->dcst<PointerType>()) {
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    if (p->len == ArrayType::kUnLen)
      return llvm::PointerType::get(mCtx, 0);
    return llvm::ArrayType::get(getSubType(type), p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto&& param : p->params)
      pty.push_back(self(param));
    return llvm::FunctionType::get(getSubType(type), std::move(pty), false);
  }''', 1)

with open('task/3/EmitIR.cpp', 'w') as f:
    f.write(content)
print('Fixed type handler')
